'use strict';

const RESP_OK = '{"ok":true,"data":{"id":101,"status":"PAGO","total":"120.5","criadoEm":"2026-01-01T10:00:00Z"}}';
const RESP_ERR = '{"ok":false,"error":{"code":"NOT_FOUND","message":"Pedido não encontrado"}}';
const RESP_BROKEN = '{"ok":true,"data":'; // JSON inválido

const RESP_BAD_TYPES = '{"ok":true,"data":{"id":"x","status":null,"total":"abc","criadoEm":"nao-data"}}';

function safeJsonParse(text) {
  try {
    return { ok: true, value: JSON.parse(text) };
  } catch {
    return { ok: false, msg: 'JSON inválido' };
  }
}

function toNumberOrNull(v) {
  if (v === null || v === undefined) return null;
  const n = (typeof v === 'number') ? v : Number(String(v).trim());
  return Number.isNaN(n) ? null : n;
}

function toDateOrNull(v) {
  if (v === null || v === undefined) return null;
  const d = new Date(String(v));
  return Number.isNaN(d.getTime()) ? null : d;
}

function isPlainObject(x) {
  return typeof x === 'object' && x !== null && !Array.isArray(x);
}

function parseEnvelope(text) {
  const parsed = safeJsonParse(text);
  if (!parsed.ok) return { ok: false, msg: parsed.msg };

  const root = parsed.value;
  if (!isPlainObject(root)) return { ok: false, msg: 'resposta inválida' };

  if (root.ok === true) {
    return { ok: true, data: root.data };
  }

  // Erro
  const code = String(root?.error?.code ?? 'ERROR');
  const message = String(root?.error?.message ?? 'erro');
  return { ok: false, msg: message, code };
}

function parsePedido(data) {
  if (!isPlainObject(data)) return { ok: false, msg: 'data inválido' };

  const id = toNumberOrNull(data.id);
  const total = toNumberOrNull(data.total);
  const criadoEm = toDateOrNull(data.criadoEm);
  const status = String(data.status ?? '').trim();

  if (id === null) return { ok: false, msg: 'id inválido' };
  if (total === null) return { ok: false, msg: 'total inválido' };
  if (!criadoEm) return { ok: false, msg: 'criadoEm inválido' };
  if (status.length === 0) return { ok: false, msg: 'status inválido' };

  return { ok: true, pedido: { id, total, criadoEm, status } };
}

function getPedidoFromApiText(text) {
  const env = parseEnvelope(text);
  if (!env.ok) return env; // { ok:false, msg, code? }

  const parsed = parsePedido(env.data);
  if (!parsed.ok) return parsed;

  return { ok: true, value: parsed.pedido };
}

console.log(getPedidoFromApiText(RESP_OK));
console.log(getPedidoFromApiText(RESP_ERR));
console.log(getPedidoFromApiText(RESP_BROKEN));
console.log(getPedidoFromApiText(RESP_BAD_TYPES));
